    "file": "src/vs/editor/common/model/textModelSearch.ts",
    "line": 489,
    "severity": "critical",
    "description": "The isValidMatch() function uses OR (||) instead of AND (&&) when checking word boundaries. For whole-word search, BOTH the left AND right boundaries must be word boundaries. Using OR accepts matches where only one side is a boundary (e.g., matching 'test' in 'test123' with whole-word mode enabled). This breaks whole-word find operations and affects any feature using word-boundary matching.",
    "fix_patch": "--- a/src/vs/editor/common/model/textModelSearch.ts
+++ b/src/vs/editor/common/model/textModelSearch.ts
@@ -486,7 +486,7 @@

 export function isValidMatch(wordSeparators: WordCharacterClassifier, text: string, textLength: number, matchStartIndex: number, matchLength: number): boolean {
 	return (
-		leftIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
-		|| rightIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
+		leftIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
+		&& rightIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
 	);
 }
"
  },
  {
    "file": "src/vs/editor/common/languageFeatureRegistry.ts",
    "line": 195,
    "severity": "critical",
    "description": "The score comparison in _compareByScoreAndTime() is inverted. When a._score < b._score (lower score), it returns -1, causing lower scores to appear first in the sorted array. However, higher scores should indicate higher priority/relevance and must appear first for proper provider ordering. The time comparison correctly prioritizes newer registrations (returns 1 for lower time), but score comparison is backwards, causing providers with worse matches to be prioritized over better matches.",
    "fix_patch": "--- a/src/vs/editor/common/languageFeatureRegistry.ts
+++ b/src/vs/editor/common/languageFeatureRegistry.ts
@@ -192,10 +192,10 @@
 	private static _compareByScoreAndTime(a: Entry<any>, b: Entry<any>): number {
 		if (a._score < b._score) {
-			return -1;
+			return 1;
 		} else if (a._score > b._score) {
-			return 1;
+			return -1;
 		}

 		// De-prioritize built-in providers
"
  }
]

